// ============================================================
// DashboardPage.jsx — Updated with revamped tagihan widget
// ============================================================
import { useMemo } from 'react';
import StatCard from '../components/StatCard';
import BarChartBulanan from '../components/charts/BarChartBulanan';
import PieChartKategori from '../components/charts/PieChartKategori';
import { fmtRp, fmtDate, monthName, fullMonth } from '../utils/format';
import { filterByMonth, sumBy, today } from '../utils/helpers';

export default function DashboardPage({ data }) {
  const { transaksi, tagihan, hutang, piutang, aset, saldoAwal } = data;
  const now      = new Date();
  const curMonth = now.getMonth() + 1;
  const curYear  = now.getFullYear();
  const curKey   = `${curYear}-${String(curMonth).padStart(2,'0')}`;

  const curTx  = useMemo(() => filterByMonth(transaksi, curKey), [transaksi, curKey]);
  const curTag = useMemo(() => filterByMonth(tagihan, curKey),   [tagihan,  curKey]);

  const totalPmsKini     = sumBy(curTx,'pemasukan');
  const totalPglHarian   = sumBy(curTx,'pengeluaran');
  const totalPglBulanan  = sumBy(curTag,'nominal');
  const totalPglKini     = totalPglHarian + totalPglBulanan;
  const bersihKini       = totalPmsKini - totalPglKini;

  const saldoAkhir = useMemo(() => {
    const txSum  = sumBy(transaksi,'pemasukan') - sumBy(transaksi,'pengeluaran');
    const tagSum = sumBy(tagihan,'nominal');
    return saldoAwal + txSum - tagSum;
  }, [transaksi, tagihan, saldoAwal]);

  const chartData = useMemo(() => Array.from({length:6},(_,i)=>{
    let m = curMonth-(5-i), y = curYear;
    if (m<=0) { m+=12; y-=1; }
    const key = `${y}-${String(m).padStart(2,'0')}`;
    const tx  = filterByMonth(transaksi, key);
    const tag = filterByMonth(tagihan, key);
    return { label:monthName(m), pemasukan:sumBy(tx,'pemasukan'), pengeluaran:sumBy(tx,'pengeluaran')+sumBy(tag,'nominal') };
  }), [transaksi, tagihan, curMonth, curYear]);

  const catData = useMemo(() => {
    const cats = {};
    transaksi.forEach(t => { if(t.pengeluaran>0) cats[t.tujuan]=(cats[t.tujuan]||0)+t.pengeluaran; });
    tagihan.forEach(t   => { if(t.nominal>0)     cats[t.alasan]=(cats[t.alasan]||0)+t.nominal; });
    return Object.entries(cats).sort((a,b)=>b[1]-a[1]).slice(0,6).map(([name,value])=>({name,value}));
  }, [transaksi, tagihan]);

  const totalPiutang       = sumBy(piutang,'jumlah');
  const totalPiutangBayar  = sumBy(piutang,'dibayar');
  const sisaPiutang        = totalPiutang - totalPiutangBayar;
  const totalAset          = aset.filter(a=>a.aktif).reduce((s,x)=>s+(x.belitotal||0),0);

  const recentTx = [...transaksi].sort((a,b)=>b.tanggal.localeCompare(a.tanggal)).slice(0,8);

  // ── Revamped tagihan widget: tagihan bulan ini + hutang kamu ─
  const tagihanBulanIni = curTag.sort((a,b)=>(a.batas||'').localeCompare(b.batas||''));
  const hutangList      = hutang.filter(h => h.status !== 'Lunas');

  const totalTagihanBulan = sumBy(curTag,'nominal');
  const totalHutangBelum  = hutangList.reduce((s,x)=>s+((x.jumlah||0)-(x.dibayar||0)),0);

  return (
    <div className="fade-in">
      <div className="stats-grid mb-4">
        <StatCard label="Saldo Saat Ini"         value={fmtRp(saldoAkhir)}  color={saldoAkhir>=0?'green':'red'} sub="Akumulasi semua transaksi" />
        <StatCard label={`Pemasukan ${fullMonth(curMonth)}`} value={fmtRp(totalPmsKini)}  color="blue"  sub={`${curTx.filter(t=>t.pemasukan>0).length} transaksi masuk`} />
        <StatCard label={`Pengeluaran ${fullMonth(curMonth)}`} value={fmtRp(totalPglKini)} color="red"  sub="Harian + Tagihan" />
        <StatCard label="Bersih Bulan Ini"        value={fmtRp(bersihKini)}  color={bersihKini>=0?'green':'red'} sub="Pemasukan − Pengeluaran" />
        <StatCard label="Sisa Piutang"            value={fmtRp(sisaPiutang)} color="yellow" sub={`Dari ${piutang.length} orang`} />
        <StatCard label="Total Investasi"         value={fmtRp(totalAset)}   color="purple" sub={`${aset.filter(a=>a.aktif).length} aset aktif`} />
      </div>

      <div className="grid-2 mb-4">
        <div className="card">
          <div className="card-title">Tren 6 Bulan Terakhir</div>
          <BarChartBulanan data={chartData} />
        </div>
        <div className="card">
          <div className="card-title">Kategori Pengeluaran (Semua Waktu)</div>
          <PieChartKategori data={catData} />
        </div>
      </div>

      <div className="grid-2">
        {/* Transaksi terbaru */}
        <div className="card">
          <div className="section-header"><div className="section-title">Transaksi Terbaru</div></div>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Tanggal</th><th>Sumber</th><th className="right">Pemasukan</th><th className="right">Pengeluaran</th></tr></thead>
              <tbody>
                {recentTx.length===0 ? (
                  <tr><td colSpan={4} className="text-center text-muted" style={{padding:28}}>Belum ada transaksi</td></tr>
                ) : recentTx.map(t=>(
                  <tr key={t.id}>
                    <td className="text-muted" style={{fontSize:'0.76rem',whiteSpace:'nowrap'}}>{fmtDate(t.tanggal)}</td>
                    <td style={{maxWidth:130}}><span className="truncate" style={{display:'block',fontSize:'0.82rem'}}>{t.sumber}</span></td>
                    <td className="td-mono td-right" style={{color:t.pemasukan>0?'var(--green)':'var(--text3)'}}>{t.pemasukan>0?fmtRp(t.pemasukan):'—'}</td>
                    <td className="td-mono td-right" style={{color:t.pengeluaran>0?'var(--red)':'var(--text3)'}}>{t.pengeluaran>0?fmtRp(t.pengeluaran):'—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Tagihan Bulanan (revamped) */}
        <div className="card">
          <div className="section-header">
            <div className="section-title">📋 Tagihan Bulanan — {fullMonth(curMonth)}</div>
            <div style={{fontSize:'0.78rem',color:'var(--text3)'}}>Total: <strong style={{color:'var(--orange)'}}>{fmtRp(totalTagihanBulan)}</strong></div>
          </div>

          {tagihanBulanIni.length===0 && hutangList.length===0 ? (
            <div className="empty-state"><div className="empty-state-icon">✅</div><p>Tidak ada tagihan & hutang bulan ini</p></div>
          ) : (
            <div>
              {tagihanBulanIni.map(t=>(
                <div key={t.id} className="dashboard-tagihan-item">
                  <div>
                    <div style={{fontWeight:600,fontSize:'0.85rem'}}>{t.alasan}{t.ket?` (${t.ket})`:''}</div>
                    <div className="text-muted text-xs" style={{marginTop:2}}>Batas: {fmtDate(t.batas)||'—'}</div>
                  </div>
                  <div style={{textAlign:'right'}}>
                    <div className="td-mono" style={{color:'var(--orange)',fontWeight:700}}>{fmtRp(t.nominal)}</div>
                    {t.status==='Sudah dibayar'
                      ? <span className="badge green" style={{marginTop:3}}>✓ Lunas</span>
                      : <span className="badge yellow" style={{marginTop:3}}>{t.status}</span>
                    }
                  </div>
                </div>
              ))}

              {hutangList.length>0 && (
                <>
                  <div style={{fontSize:'0.7rem',fontWeight:700,textTransform:'uppercase',letterSpacing:'1px',color:'var(--text3)',padding:'10px 0 4px'}}>Hutang Kamu</div>
                  {hutangList.slice(0,3).map(h=>{
                    const sisa = (h.jumlah||0)-(h.dibayar||0);
                    return (
                      <div key={h.id} className="dashboard-tagihan-item">
                        <div>
                          <div style={{fontWeight:600,fontSize:'0.85rem'}}>{h.nama||h.dari}</div>
                          <div className="text-muted text-xs" style={{marginTop:2}}>{h.ket||'—'}</div>
                        </div>
                        <div style={{textAlign:'right'}}>
                          <div className="td-mono" style={{color:'var(--red)',fontWeight:700}}>{fmtRp(sisa)}</div>
                          <span className="badge red" style={{marginTop:3}}>Belum Lunas</span>
                        </div>
                      </div>
                    );
                  })}
                  {hutangList.length>3 && <div className="text-muted text-xs" style={{paddingTop:6}}>+{hutangList.length-3} hutang lainnya...</div>}
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
